// ---- Pillar 2: Article Writer — Keyword → Groq outline+draft → WordPress ----
// Input: { keyword: '...', pillar: 'latam|ai|gtm', word_count: 1500 }
// LLM chain: Groq 70b (primary) → Cerebras 70b → Sambanova 405B
// Two-pass: outline first (cheap, fast), then full article (keeps structure tight)
// Cost optimisation: skip if keyword already has status='published' in content_pipeline
const ENV = (typeof $env !== 'undefined' && $env) ? $env : process.env;
const b = $json.body || $json;

const keyword  = String(b.keyword  || '').trim();
const pillar   = String(b.pillar   || 'gtm').trim();
const wordTarget = parseInt(b.word_count || 1500);
if (!keyword) return [{ json: { ok: false, error: 'keyword is required' } }];

// 0) Dedup: check if already published
if (ENV.SUPABASE_URL) {
  const existing = await this.helpers.httpRequest({
    method: 'GET',
    url: `${ENV.SUPABASE_URL}/rest/v1/content_pipeline?keyword=eq.${encodeURIComponent(keyword)}&status=eq.published&select=id,status`,
    headers: { apikey: ENV.SUPABASE_ANON_KEY, Authorization: `Bearer ${ENV.SUPABASE_ANON_KEY}` },
    json: true, timeout: 10000
  }).catch(() => []);
  if (existing.length) return [{ json: { ok: false, skipped: true, reason: 'Already published', keyword } }];
}

// LLM fallback helper
const LLM_PROVIDERS = [
  { url: 'https://api.groq.com/openai/v1/chat/completions', key: ENV.GROQ_API_KEY, model: 'llama-3.3-70b-versatile' },
  { url: 'https://api.cerebras.ai/v1/chat/completions', key: ENV.CEREBRAS_API_KEY, model: 'llama3.1-70b' },
  { url: 'https://api.sambanova.ai/v1/chat/completions', key: ENV.SAMBANOVA_API_KEY, model: 'Meta-Llama-3.1-405B-Instruct' },
];
async function callLLM(system, user, maxTokens, jsonMode = false) {
  for (const p of LLM_PROVIDERS) {
    if (!p.key) continue;
    try {
      const body = { model: p.model, messages: [{role:'system',content:system},{role:'user',content:user}], temperature: 0.4, max_tokens: maxTokens };
      if (jsonMode) body.response_format = { type: 'json_object' };
      const res = await this.helpers.httpRequest({
        method: 'POST', url: p.url,
        headers: { Authorization: `Bearer ${p.key}`, 'Content-Type': 'application/json' },
        body: JSON.stringify(body), json: true, timeout: 60000
      });
      return res.choices[0].message.content;
    } catch { continue; }
  }
  throw new Error('All LLM providers failed');
}

// 1) Generate outline
const outlineSys = `You are a senior B2B content strategist for Markexis — specialists in LatAm Market Entry, AI Marketing Implementation, and Revenue Growth/GTM Strategy. Write SEO-optimised, expert-level B2B content that demonstrates deep domain expertise.`;
const outlineUser = `Create a detailed article outline for the keyword: "${keyword}"
Pillar: ${pillar}
Target word count: ${wordTarget}

Return JSON: { "title": "...", "meta_description": "...", "sections": [{"h2": "...", "points": ["...","..."]}] }`;

let outline;
try {
  outline = JSON.parse(await callLLM.call(this, outlineSys, outlineUser, 1024, true));
} catch (e) {
  return [{ json: { ok: false, error: `Outline failed: ${e.message}`, keyword } }];
}

// 2) Write full article from outline
const articleSys = `You are an expert B2B content writer for Markexis. Write detailed, authoritative articles that rank on Google and convert B2B readers.
Rules:
- Write in clear, direct, expert tone — no fluff, no generic statements
- Every claim backed by specific examples, data, or frameworks
- Natural keyword usage — primary keyword in H1, first 100 words, 2-3 H2s, conclusion
- Include actionable takeaways in every section
- No em-dashes. No AI clichés (game-changer, leverage, unlock, delve, robust)
- Output clean HTML (h2, h3, p, ul, li tags only — no html/body/head wrapper)`;

const outline_text = outline.sections?.map(s => `## ${s.h2}\n${s.points?.join('\n') || ''}`).join('\n\n') || '';
const articleUser = `Write a ${wordTarget}-word article:\nTitle: ${outline.title}\nKeyword: ${keyword}\n\nOutline:\n${outline_text}\n\nWrite the complete article in HTML format.`;

let articleHTML;
try {
  articleHTML = await callLLM.call(this, articleSys, articleUser, Math.min(wordTarget * 2, 8000));
} catch (e) {
  return [{ json: { ok: false, error: `Article write failed: ${e.message}`, keyword, outline } }];
}

// 3) Store draft in Supabase
const row = {
  keyword,
  topic: outline.title,
  status: 'review',
  pillar,
  word_count_target: wordTarget,
  article_draft: articleHTML,
  updated_at: new Date().toISOString()
};

let supaId = null;
if (ENV.SUPABASE_URL) {
  const sr = await this.helpers.httpRequest({
    method: 'POST',
    url: `${ENV.SUPABASE_URL}/rest/v1/content_pipeline?on_conflict=keyword`,
    headers: {
      apikey: ENV.SUPABASE_ANON_KEY, Authorization: `Bearer ${ENV.SUPABASE_ANON_KEY}`,
      'Content-Type': 'application/json', Prefer: 'resolution=merge-duplicates,return=representation'
    },
    body: JSON.stringify(row), json: true, timeout: 20000
  }).catch(e => ({ error: e.message }));
  supaId = Array.isArray(sr) ? sr[0]?.id : null;
}

// 4) Publish to WordPress (if credentials set)
let wpResult = null;
if (ENV.WORDPRESS_URL && ENV.WORDPRESS_USER && ENV.WORDPRESS_APP_PASSWORD) {
  const auth = Buffer.from(`${ENV.WORDPRESS_USER}:${ENV.WORDPRESS_APP_PASSWORD}`).toString('base64');
  const wpRes = await this.helpers.httpRequest({
    method: 'POST',
    url: `${ENV.WORDPRESS_URL}/wp-json/wp/v2/posts`,
    headers: { Authorization: `Basic ${auth}`, 'Content-Type': 'application/json' },
    body: JSON.stringify({
      title: outline.title,
      content: articleHTML,
      status: 'draft', // publish manually after review
      excerpt: outline.meta_description || ''
    }),
    json: true, timeout: 30000
  }).catch(e => ({ error: e.message }));
  wpResult = wpRes.id ? { post_id: wpRes.id, link: wpRes.link } : { error: wpRes.error };
}

return [{ json: { ok: true, keyword, title: outline.title, word_count: articleHTML.split(' ').length, supabase_id: supaId, wordpress: wpResult, status: 'review' } }];
